import { Add } from '@mui/icons-material';
import { Fab, Grid } from '@mui/material';
import { Container } from '@mui/system';
import React, { useContext, useEffect } from 'react';
import { Link,  useNavigate } from 'react-router-dom';
import { ListingContext } from './contexts/ListingContext';
import FilterBar from './FilterBar';
import ListingCard from './ListingCard';
import {useIsAuthenticated} from 'react-auth-kit'

function Listings() {
    const { resetFilters, currentListings, findData, model, year, trim, interior, exterior, autopilot, sort, setMessage, setMessageStatus,sortAllListings, loading, setLoading } = useContext(ListingContext)

    const navigate = useNavigate()
    const isAuthenticated = useIsAuthenticated()

    useEffect(() => {
        // getAllListings()
        resetFilters()
        findData()
        sortAllListings()
        setLoading(false)
    }, [])

    useEffect(() => {
        sortAllListings()
    },[sort])

    useEffect(() => {
        findData()
        sortAllListings()
    }, [model, year, trim, interior, exterior, autopilot])

    const handleClick = () => {
        if (isAuthenticated()) {
            navigate('/listings/new')
        } else {
            navigate('/login')
            setMessageStatus('error')
            setMessage('You must be logged in to create a new listing')
        }
    }



    return (
        <Container fixed>
            <Grid container rowGap={2}>
            <FilterBar />
            <Grid container item rowGap={4}>
            {currentListings.map(listing => (
                <Link key={listing._id} to={`/listings/${listing._id}`} style={{textDecoration: 'none', width:'100%'}}>
                <ListingCard listing={listing}
                // images={(listing.images) ? listing.images[0].url : "https://res.cloudinary.com/deuft4auk/image/upload/v1661794348/Tesla/0x0-0x0-Service_21_fatbwh.jpg"} 
                />
                </Link>
            ))}
            </Grid>
            </Grid>
            <Fab onClick={handleClick} color="primary" aria-label="add" style={{zIndex: 20, position: 'fixed', bottom: 40, right: 40}} >
  <Add />
</Fab>

        </Container>
    );
}

export default Listings;
