import React, { useContext } from "react";
import Dialog from '@mui/material/Dialog';
import DialogTitle from '@mui/material/DialogTitle';
import { List, ListItem, ListItemAvatar, ListItemText, Avatar, CircularProgress } from "@mui/material";
import { Check, Close } from "@mui/icons-material";
import { blue, red } from "@mui/material/colors";
import { ListingContext } from "./contexts/ListingContext";
import { useNavigate, useParams } from "react-router-dom";

export default function DeleteConfirmation(props) {
    const { deleteListing, isAuthor, loading, setLoading } = useContext(ListingContext)
    const { id } = useParams()
    const navigate = useNavigate()

    return (
        <div>
            <Dialog open={loading} onClose={()=>setLoading(false)} aria-labelledby='loading' PaperProps={{
    style: {
      backgroundColor: 'transparent',
      boxShadow: 'none',
    },
  }}>
            <CircularProgress />
            </Dialog>
        </div>
    );
}


