import { ArrowBack, Delete, Edit } from '@mui/icons-material';
import { Grid, Button, Typography } from '@mui/material';
import React, { useContext, useEffect, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import { ListingContext } from './contexts/ListingContext';
import ShowGallery from './ShowGallery';
import ShowCardInfo from './ShowCardInfo';
import { useAuthUser, useIsAuthenticated } from 'react-auth-kit'
import ListingDataService from './services/listing.service'
import DeleteConfirmation from './DeleteConfirmation';
import CommentForm from './CommentForm';
import CommentList from './CommentList';

export default function Show() {

    const { setIsAuthor, isAuthor, setComments, setLoading } = useContext(ListingContext)
    const { id } = useParams()
    const [currentUserId, setCurrentUserId] = useState('')
    const [currentListing, setCurrentListing] = useState({ images: [] })
    const [currentListingAuthor, setCurrentListingAuthor] = useState('')
    const [deleteDialogOpen, setDeleteDialogOpen] = useState(false)
    const auth = useAuthUser()
    const isAuthenticated = useIsAuthenticated()

    const handleOpen = () => {
        setDeleteDialogOpen(true)
    }

    const handleClose = () => {
        setDeleteDialogOpen(false);
    };

    useEffect(() => {
        setLoading(true)
        ListingDataService.get(id)
            .then(({ data }) => {
                console.log(data.images)
                setComments(data.comments)
                setCurrentListing(data)
                setCurrentListingAuthor(data.author._id)
                if (isAuthenticated()) {
                    setCurrentUserId(auth()._id)
                }
                setLoading(false)
            })
    }, [])

    useEffect(() => {
        if (isAuthenticated() && auth()._id === currentListingAuthor) {
            setIsAuthor(true)
        } else {
            setIsAuthor(false)
        }
    }, [currentUserId])

    const navigate = useNavigate()
    const { images } = currentListing


    let imgs = currentListing.images.map(img => img.url)

    const handleBack = () => {
        navigate('/listings')
    }

    // const handleDelete = () => {
    //     if (isAuthor) {
    //         deleteListing(id)
    //         navigate('/listings')
    //     }
    // }

    const handleEdit = () => {
        if (isAuthor) {
            navigate(`/listings/${id}/edit`)
        }
    }


    return (
        <>
            <DeleteConfirmation open={deleteDialogOpen} handleClose={handleClose} />
            <Grid container item
                justifyContent='space-around' rowGap={2}>
                <Grid item container direction='row' width='100%' marginY='calc(13.5px/2)' columnGap={2} xs={11}>
                    <Button
                        startIcon={<ArrowBack />}
                        onClick={handleBack}
                        variant='outlined'
                    >
                        Back
                    </Button>
                    {isAuthor &&
                        <>
                            <Button
                                startIcon={<Edit />}
                                onClick={handleEdit}
                                variant='outlined'
                                color='primary'
                            >
                                Edit
                            </Button>
                            <Button
                                startIcon={<Delete />}
                                onClick={handleOpen}
                                variant='outlined'
                                color='error'
                            >
                                Delete
                            </Button>
                        </>
                    }
                </Grid>
                <Grid item container xs={11} md={5}>
                    <Grid item container xs={12}>
                    <ShowGallery
                        images={images} defaultMain={imgs[0]}
                    // images={currentListing.images || []}
                    // images={currentListing.images.length ? currentListing.images : ['https://res.cloudinary.com/deuft4auk/image/upload/v1662708360/tesla/lhvqche82wz6rvl4qbvw.jpg']}
                    />
                    </Grid>

                <Grid item container direction='row' alignItems='flex-start' xs={12}>
                    <ShowCardInfo showCard={true} {...currentListing} {...currentListing.author} />
                </Grid>
                </Grid>
                <Grid item container direction='column' xs={11} md={5} rowGap={4}>
                    {auth() ?
                        <CommentForm /> :
                        <Link to='/login' style={{ textDecoration: 'none' }}>
                            <Typography variant='body1'>
                                Log in to leave a comment!
                            </Typography>
                        </Link>
                    }
                    {/* </Grid>
                <Grid item container xs={11} md={5}> */}

                    <CommentList id={id} />
                </Grid>
                {/* <Grid item container xs={11} lg={5}>
                <Typography variant='h4'>
                    Comments
                </Typography>
            </Grid> */}
            </Grid>
        </>
    );
}